changeSet.sql:
CREATE TABLE organizations_metadata ( id serial, organization_id int4 NOT NULL, key character varying (255) NOT NULL, value character varying (4096),
CONSTRAINT pk_organizations_metadata PRIMARY KEY (id), CONSTRAINT fk_organizations_metadata_to_organizations FOREIGN KEY (organization_id) REFERENCES organizations(id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION );
CREATE INDEX i_organizations_metadata_organization_id ON organizations_metadata USING btree (organization_id); CREATE UNIQUE INDEX ui_organizations_metadata_organization_id_key ON organizations_metadata (organization_id, key);
